#include <iostream>
#include <fstream>
using namespace std;

int main() {
 ifstream infile("data.txt");
 char ch;
 int count = 0;

 // Method 1: Using stream's bool conversion
 while (infile.get(ch)) {
 cout << ch;
 count++;
 }

