#include <fstream>
#include <string>
using namespace std;

int main() {
 ifstream infile("data.txt");
 string line;
 int lineCount = 0;

 // getline() returns false at EOF
 while (getline(infile, line)) {
 cout << line << endl;
 lineCount++;
 }

 cout << "Total lines: " << lineCount << endl;
 infile.clear(); // Clear EOF flag if needed for further reading
 infile.close();
 return 0;
}

#include <iostream>
#include <fstream>
using namespace std;

int main() {
 ifstream infile("binary.dat", ios::binary);
 ofstream outfile("copy.dat", ios::binary);

 const int BUFFER_SIZE = 1024;
 char buffer[BUFFER_SIZE];

 if (!infile.is_open() || !outfile.is_open()) {
 cout << "Error opening files!" << endl;
 return 1;
 }

 // Read binary data until EOF
 while (infile.read(buffer, BUFFER_SIZE)) {
 streamsize bytesRead = infile.gcount();
 outfile.write(buffer, bytesRead);
 }

 // Check if we stopped due to EOF or error
 if (infile.eof()) {
 cout << "EOF reached. Copy complete." << endl;
 } else if (infile.bad()) {
 cout << "Fatal I/O error!" << endl;
 }

 infile.close();
 outfile.close();
 return 0;
}

#include <iostream>
#include <fstream>
using namespace std;

void method1_eofFlag(ifstream& infile) {
 char ch;
 while (!infile.eof()) {
 infile.get(ch);
 if (!infile.eof()) cout << ch; // Avoid double processing
 }
 infile.clear();
}

void method2_streamBool(ifstream& infile) {
 char ch;
 while (infile.get(ch)) {
 cout << ch;
 }
 infile.clear();
}

void method3_peek(ifstream& infile) {
 while (infile.peek() != EOF) {
 char ch = infile.get();
 cout << ch;
 }
 infile.clear();
}

int main() {
 ifstream infile("test.txt");
 if (!infile) {
 cout << "File not found!" << endl;
 return 1;
 }

 cout << "Method 2 (Recommended):" << endl;
 method2_streamBool(infile);

 return 0;
}

#include <iostream>
#include <fstream>
using namespace std;

void checkStreamState(ifstream& infile) {
 if (infile.good()) {
 cout << "Stream state: Good - no errors" << endl;
 }
 if (infile.eof()) {
 cout << "Stream state: EOF reached" << endl;
 }
 if (infile.fail()) {
 cout << "Stream state: Fail (EOF or type mismatch)" << endl;
 }
 if (infile.bad()) {
 cout << "Stream state: Bad - fatal I/O error" << endl;
 }
}

int main() {
 ifstream infile("data.txt");

 // Check if file opened successfully
 if (!infile) {
 cout << "Error: Cannot open file!" << endl;
 return 1;
 }

 char data;
 while (infile.get(data)) {
 cout << data;
 }

 // Check final state
 checkStreamState(infile);

 // If we want to read again from beginning
 infile.clear(); // Clear all flags
 infile.seekg(0); // Go back to beginning

 cout << "\n--- Reading again from start ---" << endl;
 while (infile.get(data)) {
 cout << data;
 }

 infile.close();
 return 0;
}
